def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        decay = 1.0
        amplify = 1.0
        bias = 0.0
        modifier = 1.0
        factor = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                decay *= (0.99 + 0.005 * j)
            else:
                amplify *= (1.02 - 0.004 * j)
            term1 = np.tanh((cap - item * j) / (j + 1))
            term2 = np.sqrt(abs(item - cap / (j + 0.5)))
            weighted = (term1 + term2) * amplify / (decay + j * 0.1)
            if ratio < 0.15 * j:
                score += weighted * np.cos(j * ratio * np.pi / 4)
            else:
                score += weighted * np.log1p(j + ratio)
            if (cap + j*j*j) % 11 == 0:
                score *= 1.07
            elif (cap * j) % 13 == 0:
                score *= 0.93
            if j == 7:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff >= 0:
                        if diff % (k+3) == 0:
                            bias += np.log1p(diff) / (k + 2)
                        else:
                            bias -= np.exp(-diff / (k + 5))
                    else:
                        bias -= abs(diff) ** 1.5 / (k + 4)
            if ratio > 0.8 and j % 4 == 0:
                modifier *= (1.12 + 0.015 * j)
            elif ratio < 0.25 and j % 5 == 0:
                modifier *= (0.85 - 0.02 * j)
            if j % 6 == 1 and cap % (j + 2) == 0:
                bias += np.sin(ratio * j) * 0.7
            if j % 3 == 0:
                factor *= (1 + 0.008 * j) if cap % (j + 3) == 0 else (1 - 0.007 * j)
        score += bias * 0.9
        score *= modifier
        score = score * factor
        if score < 0:
            priorities[i] = -score * (np.log1p(cap * item) + np.sqrt(cap) + 1)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio)**1.1
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**3)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 5 == 0:
            priorities[i] *= 1.03
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
        if np.isclose(cap, item):
            priorities[i] *= 1.15
    return priorities
